import{_ as a,o as t,c as o,a2 as s}from"./chunks/framework.D5wUhsuj.js";const n="/docs/assets/system-status-user-menu.MiOG3WJH.png",r="/docs/assets/system-status-quota-overview.Cw-nhk9h.png",l="/docs/assets/system-status-cleanup-dialog.Du808CFl.png",i="/docs/assets/system-status-admin-health.DIRXVQc1.png",d="/docs/assets/system-status-backend-info.BeVbALXf.png",b=JSON.parse('{"title":"System Status","description":"","frontmatter":{},"headers":[],"relativePath":"platform/system_status.md","filePath":"platform/system_status.md","lastUpdated":1783462857000}'),c={name:"platform/system_status.md"};function p(h,e,m,u,g,k){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="system-status" tabindex="-1">System Status <a class="header-anchor" href="#system-status" aria-label="Permalink to &quot;System Status&quot;">​</a></h1><p>The <strong>System Status</strong> page is available from the prokube user menu. It shows workspace pod quota for workspaces you can access. For administrators, it also shows live backend component health checks.</p><p>Use this page to inspect pod quota pressure before starting new workloads, clean up completed pipeline pods, and perform a quick platform health check when you have administrator privileges.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Open the user menu in the prokube UI and select <strong>System Status</strong>.</p><p><img src="'+n+'" alt="System Status in the user menu" loading="lazy"></p><p>The page may also be available directly at <code>/system-status</code>.</p><p>All authenticated users can open the page to inspect workspace pod quota. The <strong>Component Health</strong> and <strong>Backend Info</strong> sections are visible only to realm administrators.</p><h2 id="workspace-pod-quota" tabindex="-1">Workspace Pod Quota <a class="header-anchor" href="#workspace-pod-quota" aria-label="Permalink to &quot;Workspace Pod Quota&quot;">​</a></h2><p>The top section shows pod quota usage across all workspaces you can access. Each workspace card shows:</p><ul><li>workspace name;</li><li>your workspace role;</li><li>pod quota usage, when loaded;</li><li>running pod count;</li><li>pending pod count;</li><li>completed pipeline pod count;</li><li>warning or critical state when usage approaches or exceeds the quota.</li></ul><p><img src="'+r+'" alt="Workspace pod quota overview" loading="lazy"></p><p>To keep the page responsive, quota details are not loaded for every workspace at once. The currently selected workspace is loaded automatically when it is in your accessible workspace list. If the selected workspace is not available, the first visible workspace card is loaded. Other workspace cards show <strong>Load pod quota</strong> until you load them manually.</p><p>Use <strong>Refresh</strong> on a workspace card to update that workspace&#39;s quota numbers on demand. If you have many workspaces, use <strong>Load more workspaces</strong> to show additional cards.</p><h2 id="clean-up-completed-pipeline-pods" tabindex="-1">Clean Up Completed Pipeline Pods <a class="header-anchor" href="#clean-up-completed-pipeline-pods" aria-label="Permalink to &quot;Clean Up Completed Pipeline Pods&quot;">​</a></h2><p>When a workspace has completed pipeline pods, the workspace card can show <strong>Clean up completed pipeline pods</strong>.</p><p>This action deletes completed Argo Workflows / Kubeflow Pipelines pod resources in that workspace. It does not delete running pods, pending pods, unrelated pods, pipeline metadata, artifacts, or logs.</p><p>Use this when completed pipeline pods are consuming workspace pod quota and blocking new work.</p><p><img src="'+l+'" alt="Delete Completed Pipeline Pods dialog" loading="lazy"></p><h2 id="admin-component-health" tabindex="-1">Admin Component Health <a class="header-anchor" href="#admin-component-health" aria-label="Permalink to &quot;Admin Component Health&quot;">​</a></h2><p>Realm administrators also see <strong>Component Health</strong>. This section runs live health checks against backend components and shows whether platform services are healthy, degraded, unhealthy, or disabled.</p><p>Each component card includes:</p><ul><li>component name;</li><li>health state;</li><li>check latency in milliseconds when the component is enabled;</li><li>a short detail message from the health check.</li></ul><p>Possible states:</p><table tabindex="0"><thead><tr><th>State</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Healthy</strong></td><td>The component is enabled and responded successfully.</td></tr><tr><td><strong>Degraded</strong></td><td>The component responded, but the check found a non-fatal issue.</td></tr><tr><td><strong>Unhealthy</strong></td><td>The component is enabled but failed its health check.</td></tr><tr><td><strong>Disabled</strong></td><td>The component is not enabled in the current deployment.</td></tr></tbody></table><p>The summary bar counts healthy, degraded, unhealthy, and disabled components.</p><p><img src="'+i+'" alt="Admin Component Health" loading="lazy"></p><h2 id="admin-backend-info" tabindex="-1">Admin Backend Info <a class="header-anchor" href="#admin-backend-info" aria-label="Permalink to &quot;Admin Backend Info&quot;">​</a></h2><p>Realm administrators also see <strong>Backend Info</strong>, including backend version and enabled backend modules.</p><p>Use this to confirm which backend version and modules are active in the current deployment before debugging feature behavior.</p><p><img src="'+d+'" alt="Backend Info" loading="lazy"></p><h2 id="refresh-checks" tabindex="-1">Refresh Checks <a class="header-anchor" href="#refresh-checks" aria-label="Permalink to &quot;Refresh Checks&quot;">​</a></h2><p>Click <strong>Run All Checks</strong> to rerun administrator health checks manually.</p><p>Enable <strong>Auto-refresh</strong> when you want the page to rerun checks periodically while watching a rollout or investigating an incident. Auto-refresh runs every 30 seconds.</p><p>Use manual refresh for normal checks. Use auto-refresh only while actively monitoring; for long-running observability, use Grafana, Prometheus, and alerting instead.</p><h2 id="recommended-workflow" tabindex="-1">Recommended Workflow <a class="header-anchor" href="#recommended-workflow" aria-label="Permalink to &quot;Recommended Workflow&quot;">​</a></h2><p>When a user reports that workloads cannot start:</p><ol><li>Open <strong>System Status</strong> from the user menu.</li><li>Check the workspace pod quota card for the affected workspace.</li><li>If completed pipeline pods are consuming quota, clean them up from the workspace card.</li><li>If you are an administrator, run <strong>Component Health</strong> checks.</li><li>Use unhealthy or degraded component messages as a starting point, then continue in Grafana, Loki, Argo CD, Kubernetes events, or pod logs.</li></ol><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>Workspace pod quota cards show only workspaces you can access.</li><li>Quota details are loaded per workspace, not all at once.</li><li>Component health checks are administrator-only.</li><li>The page checks backend components and integrations, not every workload in every workspace.</li><li>A healthy component status means the health check passed; it does not guarantee that all user workflows are healthy.</li><li>A disabled status can be expected when a module is intentionally not enabled in a deployment.</li><li>Detailed historical metrics, alerts, and logs remain in Grafana, Prometheus, Alertmanager, and Loki.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./kubernetes.html">Kubernetes Resources</a></li><li><a href="./observability.html">Observability</a></li><li><a href="./../mlops/pipelines.html">Pipelines</a></li><li><a href="./../admin/">Admin Documentation</a></li></ul>',42)])])}const w=a(c,[["render",p]]);export{b as __pageData,w as default};
